export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveSet = new Set(liveCells.map(([x, y]) => cellKey(x, y)));

  const candidates = new Map<string, Cell>();
  for (const [x, y] of liveCells) {
    candidates.set(cellKey(x, y), [x, y]);
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      candidates.set(cellKey(x + dx, y + dy), [x + dx, y + dy]);
    }
  }

  const result: Cell[] = [];
  for (const [, [x, y]] of candidates) {
    const count = countLiveNeighbors(x, y, liveSet);
    const alive = isLiveAt(liveSet, x, y);
    if (alive && survives(count)) result.push([x, y]);
    else if (!alive && count === 3) result.push([x, y]);
  }
  return result;
}

